-- Enrichment marathon batch: Intercom, Internxt, InvenioRDM, Inventaire, Inventree, InvGate Service Desk, InVideo, Invoice Ninja

-- ── Intercom ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$AI-first customer service platform pairing the Fin AI Agent with a shared inbox, live chat, and help center tools.$q$, short_description),
  pricing_model = COALESCE($q$Subscription (per-seat plus AI usage-based)$q$, pricing_model),
  starting_price = COALESCE($q$$29/seat/month (billed annually)$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$1,000-2,000 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Intercom Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Intercom review covering the Fin AI Agent, pricing tiers, features, pros and cons, and how it compares to Zendesk and Freshdesk for support teams.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Intercom is a customer service and engagement platform founded in 2011 in San Francisco by four Irish entrepreneurs, Eoghan McCabe, Des Traynor, Ciaran Lee and David Barrett, who built it as a tool to help SaaS companies talk to customers directly inside their own products; the company grew out of Dublin's tech scene before basing its headquarters in San Francisco, and it also maintains offices in Chicago, Dublin, Sydney and London. Over its history Intercom raised roughly 490 million dollars in venture funding across a seed round in 2012, a 6 million dollar Series A in 2013 led by Social Capital, a 23 million dollar Series B in 2014 led by Bessemer Venture Partners, a Series C round led by Index Ventures, and a 125 million dollar Series D in 2018 led by Kleiner Perkins with participation from Google Ventures; in 2026 the company also took on 250 million dollars in venture debt from Hercules Capital, and in June 2026 Salesforce announced a definitive agreement to acquire Intercom for approximately 3.6 billion dollars, with the product rebranded around its AI agent, Fin. Architecturally, Intercom is a cloud-based SaaS platform built around a shared team inbox, a customizable Messenger widget embedded in web and mobile apps, and a knowledge base/help center, all unified by Fin, an AI customer service agent introduced in 2023 that reads a company's help center and support history to autonomously resolve customer questions across chat, email and voice, escalating to human agents when needed. Core features include the shared inbox with macros and canned responses, live chat and in-app messaging, a public and private help center, proactive support tools such as banners, tours and outbound campaigns, a no-code workflow/automation builder for routing and triage, Fin Copilot which gives human agents AI-drafted replies, multilingual and multibrand support, SLA management, CSAT surveys, and prebuilt plus custom analytics dashboards; integrations cover Salesforce, HubSpot, Slack, Jira, Shopify and dozens of other tools through an open API. Pricing is structured around three seat-based plans billed per agent: Essential starts at 29 dollars per seat per month billed annually (39 dollars billed monthly) and includes the shared inbox, live chat, basic automation and a public help center; Advanced runs roughly 85 to 99 dollars per seat per month and adds multiple inboxes, an automation builder, round-robin assignment and a private or multilingual help center; Expert runs roughly 132 to 139 dollars per seat per month and adds SSO, HIPAA-eligible configurations, SLAs and multibrand messengers. Fin is billed separately on a resolution-based model at 0.99 dollars per successful outcome regardless of how many messages that resolution took, and it can also be deployed standalone on top of an existing helpdesk like Salesforce Service Cloud without requiring seat licenses; add-ons such as Fin Copilot, a Proactive Support Plus package, and pay-as-you-go channels like SMS and WhatsApp add further cost, so real-world spend for AI-heavy teams is often several times the sticker price. Intercom targets mid-market and enterprise SaaS, e-commerce and tech companies that need to combine live human support with AI automation, and it competes most directly with Zendesk, Freshdesk, HubSpot Service Hub, Salesforce Service Cloud and AI-native entrants like Ada and Decagon; its differentiation has historically been its unified messaging-first product design and, more recently, Fin's resolution-based pricing and deep integration with its own inbox and help center rather than being bolted onto a legacy ticketing system.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'baabcbd9-49ee-4844-9aae-bc407aa1c068';

