-- ── InvenioRDM ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source, turn-key research data repository platform built on CERN's Invenio framework, powering Zenodo.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted)$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Geneva, Switzerland$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$InvenioRDM Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$InvenioRDM review covering the open-source CERN repository platform behind Zenodo, its architecture, features, and comparison to DSpace and Dataverse.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$InvenioRDM is a free, open-source research data management repository platform developed by CERN and a distributed community of research institutions, built on top of CERN's long-running Invenio framework, which the organization originally created to power large-scale document repositories such as the CERN Document Server and, later, the preprint and dataset repository Zenodo, launched in 2013 in partnership with OpenAIRE and the European Commission. InvenioRDM was conceived as a next-generation, turn-key rebuild of that framework aimed at giving any research institution the same repository capabilities that power Zenodo, without requiring institutions to build custom software; the project reached its v1.0 milestone in February 2021 as an early demo-ready release, followed by the first production-suitable release, v6.0, in August 2021, and Zenodo itself completed its migration onto the InvenioRDM codebase in October 2023, validating the platform at very large scale across millions of records and petabytes of data. Governance is led by CERN for the benefit of the wider community, with active development and steering contributions from partner institutions including Caltech, TU Graz, Northwestern University and CERN openlab under the umbrella of the Invenio Collaboration; the project is fully open source, with all code hosted publicly on GitHub. Architecturally, InvenioRDM is a Python-based application built on Flask and Invenio-Records-Resources, using PostgreSQL for relational data, OpenSearch or Elasticsearch for full-text and faceted search, Celery and Redis for background task processing, and a React and SASS-based frontend; it exposes REST and OAI-PMH APIs, integrates with DataCite for DOI minting, supports ORCID and ROR identifiers, controlled vocabularies, community-based curation workflows, granular access controls and embargoes, versioned records, and rich metadata schemas aligned with FAIR data principles, and it is designed to scale from a handful of records to well over a hundred million, deployable on bare metal, virtual machines, or container platforms like Docker and Kubernetes. Because it is open-source software rather than a commercial SaaS product, there is no license fee: institutions download and self-host InvenioRDM for free, though they bear their own infrastructure and systems-administration costs, and a small number of managed-hosting vendors and consultancies offer paid implementation and hosting services on top of the free codebase. The target audience is universities, national laboratories, scientific consortia, libraries and funders that need to host FAIR, citable, DOI-assigned research datasets, software and publications in compliance with funder open-data mandates such as those from the EU, NIH and NSF; InvenioRDM's most direct competitors are other open-source repository platforms such as DSpace, Dataverse, Fedora and CKAN, as well as commercial hosted options like Figshare, and it differentiates itself through its direct lineage to Zenodo, arguably the most widely used general-purpose research data repository in the world, its modern API-first architecture, and its backing by CERN's decades of large-scale scientific data infrastructure experience.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '1b860b3a-7f1c-4237-9c04-9f584f03194c';

