-- ── Inventaire ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free, open-source peer-to-peer app for cataloguing personal book collections and lending, sharing or gifting books.$q$, short_description),
  pricing_model = COALESCE($q$Free / Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$France$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Inventaire Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Inventaire review covering the open-source, Wikidata-federated book inventory app, its features, self-hosting, and alternatives like Goodreads.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Inventaire is a free, open-source, peer-to-peer application for cataloguing personal book collections and connecting readers so they can lend, borrow, sell or give away books within their own social network, built by a small nonprofit collective led by French developer Maxime Lathuiliere, who began working on the project around 2015 and later formalized it, together with a co-founder known as Jums, as a French nonprofit association called Inventaire in 2019 so the founders could work on it as paid staff funded through grants, donations and consulting rather than venture capital. The project's flagship instance runs at inventaire.io, but the codebase itself is fully open source, licensed under the AGPLv3 and hosted on Codeberg, and anyone can self-host their own federated instance rather than being locked into the main site; funding has come substantially from NLnet Foundation grants supporting decentralization and self-hosting work under NGI Zero programs. Technically, Inventaire's core innovation is that its book catalog is not a proprietary database but a CC0-licensed, Wikidata-federated bibliographic graph: rather than maintaining its own siloed metadata, Inventaire reuses, extends and contributes back to Wikidata, linking books, authors, works and editions to Wikipedia, national library catalogs, and other resources in the broader Wikimedia and Linked Open Data ecosystem, so building an inventory on Inventaire also enriches an open multilingual knowledge graph anyone can query. Core features include scanning ISBN barcodes or searching titles to add books to a personal shelf, tagging each copy as available to lend, sell, or give away, browsing what people in your network or groups currently have listed, private messaging to arrange exchanges, wishlists, and multilingual support drawing on Wikidata's language coverage; there is no built-in payment or shipping system, since Inventaire is designed to facilitate local, trust-based, peer-to-peer exchanges rather than function as a commercial marketplace. Because it is entirely free, open-source software with no subscription tiers, there is no pricing structure to speak of: the flagship inventaire.io instance is free for anyone to use, and the software itself is free to download, modify and self-host, with the project sustained through grants and donations rather than user fees. The target audience is book lovers, reading groups, cooperative and community libraries, and members of the free-culture, open-data and Wikimedia communities who want a decentralized, privacy-respecting alternative to closed platforms like Goodreads or LibraryThing for tracking their book collections and sharing them socially; its direct points of comparison are Goodreads, owned by Amazon and focused on reviews and ratings rather than physical lending, LibraryThing, and open-source library-cataloguing tools, with Inventaire's clear differentiator being its federation with Wikidata, its AGPL open-source licensing, its non-commercial, community-governed nonprofit structure, and its explicit focus on facilitating real-world lending and gifting between people who know each other rather than algorithmic book discovery.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '17bcec27-a728-457f-9bcf-8278ac304f04';

