-- ── InvGate Service Desk ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Cloud-based ITSM and IT service desk platform with AI-assisted ticketing, low-code workflows and ITIL processes.$q$, short_description),
  pricing_model = COALESCE($q$Subscription (per-agent tiered) plus Enterprise custom pricing$q$, pricing_model),
  starting_price = COALESCE($q$$1,499/year (Starter plan, up to 5 agents)$q$, starting_price),
  founded_year = COALESCE(2008, founded_year),
  company_size = COALESCE($q$201-500 employees$q$, company_size),
  headquarters = COALESCE($q$Buenos Aires, Argentina$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Spanish$q$]::text[],
  seo_title = COALESCE($q$InvGate Service Desk Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$InvGate Service Desk review covering ITIL features, transparent per-agent pricing, AI Service Agent, and comparisons to Freshservice and Jira Service Management.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$InvGate is an IT service management (ITSM) software company founded in 2008 in Buenos Aires, Argentina, by Ariel Gesto, who serves as CEO, and Liliana Gary, who serves as President, built to offer enterprise-grade IT and service management tools without the heavy implementation costs and lengthy consulting engagements typical of legacy ITSM vendors. InvGate has grown into a global company with roughly 250 to 265 employees spread across five continents and reports around 30 million dollars in annual revenue, remaining privately held and Latin-American-founded while serving customers such as universities, government agencies and mid-size to large enterprises worldwide; the flagship product line spans InvGate Service Desk alongside a broader InvGate Service Management and asset management suite. Architecturally, InvGate Service Desk is a cloud-hosted SaaS ITSM platform with an on-premise option available at the Enterprise tier, built around a low-code workflow engine that lets administrators configure ticket types, approval chains, SLAs and OLAs and custom fields without needing professional services engagements, which the company markets as enabling go-live in a matter of weeks rather than months. Core features include ITIL-aligned incident, problem and change management, a self-service portal and knowledge base, a drag-and-drop workflow and automation builder, an AI-powered virtual service agent that can triage and resolve common requests, SLA and OLA tracking with escalation rules, multi-department and multi-brand support desks, asset and CMDB integration when paired with InvGate's asset management product, native integrations with Microsoft Teams, Slack, WhatsApp, Active Directory and SSO providers, and built-in reporting and analytics dashboards. Pricing is tiered and published transparently on InvGate's website, unlike many ITSM competitors that hide pricing behind a sales call: the Starter plan is a fixed 1,499 dollars per year for up to 5 agents with unlimited end users, SSO and basic AI hub features; the Pro plan starts around 500 dollars per agent per year, from roughly 2,500 dollars annually, for 5 to 50 agents and adds the visual workflow builder, the AI Service Agent, and Teams and WhatsApp integrations; and the Enterprise plan starts around 12,000 dollars per year with custom or unlimited agent pricing, adding on-premise deployment, concurrent seat licensing, multiple SAML and SSO configurations and dedicated support; all tiers include unlimited end users and requesters at no extra charge, which differentiates InvGate's pricing model from per-seat helpdesk tools that charge for every user who submits a ticket. The target audience is small-to-mid-size IT teams as well as larger enterprises, including higher education and government, that want ITIL-aligned service management without ServiceNow-level cost and complexity; InvGate's direct competitors include Freshservice, Jira Service Management, Zendesk for IT, SysAid and ServiceNow, and it differentiates on transparent, comparatively affordable per-agent pricing, unlimited free end-users, fast low-code implementation, and Latin-American-headquartered support and pricing that tends to undercut US and European ITSM incumbents.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '0de1e87e-9618-43ae-b91b-b9ceedf4e826';

