INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('baabcbd9-49ee-4844-9aae-bc407aa1c068', $q$Fin AI Agent$q$, $q$Autonomous AI agent that resolves customer questions across chat, email and voice using the company's help center and support history.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('baabcbd9-49ee-4844-9aae-bc407aa1c068', $q$Shared Team Inbox$q$, $q$Unified inbox with macros, canned responses and assignment rules for collaborative ticket handling.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('baabcbd9-49ee-4844-9aae-bc407aa1c068', $q$Messenger and Live Chat$q$, $q$Customizable in-app and web chat widget for real-time customer conversations.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('baabcbd9-49ee-4844-9aae-bc407aa1c068', $q$Help Center$q$, $q$Public or private self-service knowledge base with multilingual and multibrand support at higher tiers.$q$, 3);
