INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('baabcbd9-49ee-4844-9aae-bc407aa1c068', $q$SLA and CSAT Management$q$, $q$Service-level tracking, escalation rules and customer satisfaction surveys on higher-tier plans.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('baabcbd9-49ee-4844-9aae-bc407aa1c068', $q$Reporting and Analytics$q$, $q$Prebuilt and custom dashboards for response time, resolution rate and team performance.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('baabcbd9-49ee-4844-9aae-bc407aa1c068', $q$Fin AI Agent resolves a large share of routine tickets without human involvement, cutting response times$q$, 0);
