INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('baabcbd9-49ee-4844-9aae-bc407aa1c068', $q$Deep proactive messaging tools like banners, tours and outbound campaigns go beyond typical helpdesk software$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('baabcbd9-49ee-4844-9aae-bc407aa1c068', $q$Strong native integrations with Salesforce, HubSpot, Slack and other business tools$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('baabcbd9-49ee-4844-9aae-bc407aa1c068', $q$Frequent feature releases backed by heavy ongoing investment, now under Salesforce$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('baabcbd9-49ee-4844-9aae-bc407aa1c068', $q$Pricing is complex and can escalate quickly once Fin AI outcomes, seats and add-ons are combined$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('baabcbd9-49ee-4844-9aae-bc407aa1c068', $q$Advanced features like the workflow builder and SSO are locked behind higher-priced tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('baabcbd9-49ee-4844-9aae-bc407aa1c068', $q$Some users report a steep learning curve for setting up automations and reporting$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('baabcbd9-49ee-4844-9aae-bc407aa1c068', $q$Per-outcome Fin pricing makes cost forecasting difficult for high-volume support teams$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('baabcbd9-49ee-4844-9aae-bc407aa1c068', $q$Historically positioned at a premium price point compared to Zendesk or Freshdesk for small teams$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('baabcbd9-49ee-4844-9aae-bc407aa1c068', $q$What is Intercom used for?$q$, $q$Intercom is a customer service platform combining a shared inbox, live chat, a help center and an AI agent (Fin) to handle and automate customer support conversations.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('baabcbd9-49ee-4844-9aae-bc407aa1c068', $q$How much does Intercom cost?$q$, $q$Core plans start at 29 dollars per seat per month billed annually, with Advanced and Expert tiers running higher; the Fin AI Agent is billed separately at 0.99 dollars per resolved outcome.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('baabcbd9-49ee-4844-9aae-bc407aa1c068', $q$What is Fin AI Agent?$q$, $q$Fin is Intercom's AI customer service agent that autonomously answers customer questions using a company's help center and support history, escalating to humans when it cannot resolve an issue.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('baabcbd9-49ee-4844-9aae-bc407aa1c068', $q$Is there a free plan for Intercom?$q$, $q$Intercom does not offer a permanent free plan, but it does offer a free trial so teams can test the platform before subscribing.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('baabcbd9-49ee-4844-9aae-bc407aa1c068', $q$Who owns Intercom now?$q$, $q$In June 2026, Salesforce announced a definitive agreement to acquire Intercom for approximately 3.6 billion dollars.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('baabcbd9-49ee-4844-9aae-bc407aa1c068', $q$What are the main Intercom alternatives?$q$, $q$Common alternatives include Zendesk, Freshdesk, HubSpot Service Hub and Salesforce Service Cloud.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('baabcbd9-49ee-4844-9aae-bc407aa1c068', $q$AI-assisted customer support$q$, $q$Support teams use Fin to auto-resolve routine questions while agents handle complex cases via the shared inbox.$q$, $q$SaaS and tech company support teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('baabcbd9-49ee-4844-9aae-bc407aa1c068', $q$Proactive customer engagement$q$, $q$Marketing and support teams send in-app banners, product tours and outbound campaigns via Messenger.$q$, $q$E-commerce and growth teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('baabcbd9-49ee-4844-9aae-bc407aa1c068', $q$Enterprise multibrand support$q$, $q$Large organizations run SLA-backed, multibrand and multilingual help desks across regions and product lines.$q$, $q$Enterprise support organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('baabcbd9-49ee-4844-9aae-bc407aa1c068', $q$Essential$q$, $q$$29/seat/month$q$, $q$Annual (or $39/month billed monthly)$q$, NULL, $q$["Shared inbox and ticketing","Live chat and Messenger","Fin AI Agent (usage-based)","Basic automation (series)","Public help center","Standard reporting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('baabcbd9-49ee-4844-9aae-bc407aa1c068', $q$Advanced$q$, $q$$85-$99/seat/month$q$, $q$Annual$q$, NULL, $q$["Everything in Essential","Multiple team inboxes","Workflow automation builder","Round-robin assignment","Private/multilingual help center","20 free Lite seats"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('baabcbd9-49ee-4844-9aae-bc407aa1c068', $q$Expert$q$, $q$$132-$139/seat/month$q$, $q$Annual$q$, NULL, $q$["Everything in Advanced","SSO and identity management","HIPAA-eligible configuration","SLA management","Multibrand messenger and help center","50 free Lite seats"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('baabcbd9-49ee-4844-9aae-bc407aa1c068', $q$Fin AI Agent (standalone)$q$, $q$$0.99 per resolution$q$, $q$Usage-based, minimum monthly commitment$q$, NULL, $q$["Works with existing helpdesks like Salesforce","No seat costs or setup fees","Handles email, chat and phone","Customizable tone and length"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('baabcbd9-49ee-4844-9aae-bc407aa1c068', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Intercom is a customer service platform that combines a shared team inbox, live chat Messenger, help center and AI automation into one product. Founded in 2011 by Eoghan McCabe, Des Traynor, Ciaran Lee and David Barrett, it was one of the earliest companies to popularize in-app messaging as an alternative to email-only support, and it has since expanded into a full support suite used by thousands of SaaS, e-commerce and technology companies.$q$, $q$The centerpiece of Intercom's current product is Fin, an AI customer service agent launched in 2023 that reads a company's help center and past conversations to resolve customer questions autonomously across chat, email and voice, handing off to human agents only when needed. In June 2026, Salesforce agreed to acquire Intercom for approximately 3.6 billion dollars, folding the Fin AI agent and support suite into Salesforce's broader customer platform while Intercom continues to operate its existing product line.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('baabcbd9-49ee-4844-9aae-bc407aa1c068', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, Intercom offers a shared inbox with macros, canned responses and team assignment rules, a customizable Messenger widget for live chat and in-app messaging, and a public or private help center for self-service articles. A no-code workflow automation builder handles routing, triage and proactive outbound campaigns like banners and product tours, while reporting dashboards track response times, resolution rates and customer satisfaction.$q$, $q$Fin AI Agent and Fin Copilot are the platform's AI layer: Fin resolves customer questions directly, while Copilot assists human agents with AI-drafted replies and internal knowledge lookups. Higher tiers add SLA management, multibrand and multilingual help centers, SSO/identity management, and HIPAA-eligible configurations for regulated industries, alongside native integrations with Salesforce, HubSpot, Slack, Jira and Shopify.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('baabcbd9-49ee-4844-9aae-bc407aa1c068', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Intercom prices its core plans per seat: Essential starts at 29 dollars per seat per month (annual billing), Advanced runs roughly 85 to 99 dollars per seat per month, and Expert runs roughly 132 to 139 dollars per seat per month, with each tier unlocking more automation, routing, and enterprise controls. All plans include the Fin AI Agent, but Fin itself is billed separately at 0.99 dollars per resolved outcome rather than being bundled into the seat price.$q$, $q$Because of this combination of seat costs, per-outcome AI charges and optional add-ons like Fin Copilot, Proactive Support Plus, and pay-as-you-go SMS/WhatsApp channels, real-world Intercom bills for AI-heavy support teams frequently run well above the advertised starting price. Fin can also be purchased as a standalone AI agent layered on top of an existing helpdesk such as Salesforce Service Cloud, with no seat costs required.$q$]::text[], 2);
