INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Zero-knowledge encryption$q$, $q$Client-side AES-256 encryption ensures only the account holder can decrypt stored files.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Post-quantum cryptography$q$, $q$Additional encryption layer designed to resist future quantum-computing-based attacks.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Sharded file storage$q$, $q$Encrypted files are split and distributed across infrastructure rather than stored as single files.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Internxt Send$q$, $q$Encrypted file transfer tool for sharing large files securely with external recipients.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Internxt Meet and Mail$q$, $q$Encrypted video calling and email products extending the privacy suite beyond storage.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Cross-platform apps$q$, $q$Native clients for Windows, macOS, Linux, iOS and Android plus web, CLI and WebDAV access.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Lifetime storage plans$q$, $q$One-time payment plans for permanent storage allocations without recurring subscription fees.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Compliance certifications$q$, $q$GDPR, HIPAA, ISO 27001 and SOC 2 compliance backed by independent penetration testing.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$True zero-knowledge encryption means Internxt cannot access or hand over readable user data$q$, 0);
