INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Post-quantum encryption is a forward-looking differentiator versus most competitors$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$EU-based (Spain) hosting appeals to GDPR-conscious individuals and businesses$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Bundled VPN, antivirus and encrypted sharing add value beyond plain storage$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Smaller company and ecosystem than incumbents like Google Drive or Dropbox$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Fewer third-party app integrations compared to mainstream cloud storage providers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Free tier storage (1GB) is modest compared to some competitors' free offers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Collaboration features (real-time document editing, etc.) are less developed than Google Workspace$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Zero-knowledge design means lost passwords can result in permanently inaccessible data$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$What is Internxt used for?$q$, $q$Internxt is an encrypted cloud storage service used to securely store, sync and share files, photos and documents with zero-knowledge, client-side encryption.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Is Internxt really zero-knowledge?$q$, $q$Yes, files are encrypted on the user's device before upload using AES-256 and post-quantum cryptography, so Internxt itself cannot read stored data.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Does Internxt have a free plan?$q$, $q$Yes, every account includes 1GB of free storage for life with no credit card required.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$What are Internxt lifetime plans?$q$, $q$Lifetime plans are one-time payments, roughly 450 to 950 dollars, for storage allocations up to 50TB that never expire.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Where is Internxt based?$q$, $q$Internxt is headquartered in Valencia, Spain, and operates under EU data protection law.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$What are Internxt alternatives?$q$, $q$Common alternatives include Tresorit, pCloud, Proton Drive, Sync.com, Google Drive and Dropbox.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Privacy-conscious personal storage$q$, $q$Individuals store photos, documents and backups with encryption the provider itself cannot read.$q$, $q$Privacy-focused consumers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$GDPR-compliant business storage$q$, $q$EU businesses use Internxt for file storage that satisfies GDPR data residency and protection requirements.$q$, $q$European small and mid-size businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Long-term archival with lifetime plans$q$, $q$Users who want to avoid recurring subscriptions pay once for a fixed storage allocation.$q$, $q$Cost-conscious long-term storage users$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["1GB storage for life","Core apps on all platforms","Zero-knowledge encryption","Basic file sharing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Essential$q$, $q$From approximately $1-3/month$q$, $q$Monthly or annual$q$, NULL, $q$["1TB storage","VPN and antivirus included","Password-protected sharing","File versioning"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Premium / Ultimate$q$, $q$From approximately $4-10/month$q$, $q$Monthly or annual$q$, NULL, $q$["3TB-5TB storage","Full Internxt suite (Send, Meet, Mail)","CLI and WebDAV support","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Lifetime Plans$q$, $q$$450-$950 one-time$q$, $q$One-time payment$q$, NULL, $q$["Up to 50TB storage","No recurring fees","Stackable storage expansion","30-day money-back guarantee"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Internxt is a Valencia, Spain-based cloud storage company founded in 2020 by Fran Villalba Segarra with a single design premise: the provider itself should never be able to read a customer's files. It positions itself as a European, privacy-first alternative to Google Drive and Dropbox, built on zero-knowledge, client-side encryption rather than server-side encryption that the vendor can unlock.$q$, $q$Beyond core file storage, Internxt has expanded into a broader privacy suite including encrypted file transfer, video calling, email, a VPN and an antivirus tool, reflecting an ambition to offer a full alternative to mainstream cloud and productivity services for privacy-conscious users and GDPR-bound organizations.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Internxt Drive encrypts files with AES-256 client-side encryption before upload and layers in post-quantum cryptography, meaning no one but the account holder, not even Internxt staff, can decrypt stored data. Encrypted files are also sharded and distributed across infrastructure rather than kept as single whole files, adding a further layer of protection against any single point of compromise.$q$, $q$The platform ships native apps for Windows, macOS, Linux, iOS and Android plus a web client, CLI and WebDAV support, and bundles password-protected file sharing, file versioning, and the wider Internxt suite (Send, Meet, Mail, VPN, antivirus and a storage cleaner) into paid plans. Much of the client code is open source on GitHub, and the company has been independently penetration-tested and holds GDPR, HIPAA, ISO 27001 and SOC 2 compliance credentials.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Every Internxt account starts with 1GB of storage free for life with no credit card required. Paid subscription tiers scale from Essential (1TB) through Premium (3TB) to Ultimate (5TB), billed monthly or at a discount annually, with all tiers including the VPN, antivirus and password-protected sharing features rather than gating them behind separate add-ons.$q$, $q$Internxt also offers one-time lifetime plans, ranging from roughly 450 to 950 dollars for one-time storage allotments up to 50TB that never expire and carry no recurring fee, a pricing model uncommon among privacy-focused cloud providers and one the company uses to differentiate itself from subscription-only competitors like Tresorit and pCloud.$q$]::text[], 2);
