INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$Turn-key repository deployment$q$, $q$Pre-built, configurable repository platform ready to deploy without building custom software from scratch.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$DOI minting via DataCite$q$, $q$Automatic assignment of citable, persistent digital object identifiers to published records.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$FAIR metadata and controlled vocabularies$q$, $q$Rich, standards-aligned metadata schemas supporting findable, accessible, interoperable and reusable data.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$Community curation workflows$q$, $q$Configurable review and curation processes for institutional or subject-based communities.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$Versioned records and embargoes$q$, $q$Full version history alongside granular access controls and time-limited embargoes on records.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$REST and OAI-PMH APIs$q$, $q$Open APIs for programmatic ingestion, harvesting and integration with other research systems.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$Scalable architecture$q$, $q$Container-friendly design (Docker, Kubernetes) proven at Zenodo scale, from single records to over a hundred million.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$ORCID and ROR integration$q$, $q$Persistent identifier support for linking authors and institutions to published research outputs.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$Free and open source with no licensing costs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$Proven at massive scale via Zenodo, which runs on the same codebase$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$Backed by CERN and an active multi-institution developer community$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$FAIR-compliant metadata and DOI support built in from the start$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$Modern, API-first architecture that integrates well with other research systems$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$Requires technical expertise in Python, Docker and Kubernetes to self-host and maintain$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$No official vendor support line; institutions rely on community forums or paid consultancies$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$Initial setup and metadata customization can be time-consuming for smaller institutions$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$Fewer out-of-the-box integrations than commercial platforms like Figshare$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$Ongoing maintenance is required to track releases and community-driven changes$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$What is InvenioRDM used for?$q$, $q$InvenioRDM is used by universities, labs and consortia to host, curate and publish FAIR, citable research datasets, software and publications.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$Is InvenioRDM free?$q$, $q$Yes, it is free, open-source software; institutions bear only their own hosting and administration costs.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$What is the relationship between InvenioRDM and Zenodo?$q$, $q$Zenodo, the well-known European open-access repository, migrated onto the InvenioRDM codebase in October 2023, making it the platform's largest real-world deployment.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$Who maintains InvenioRDM?$q$, $q$CERN leads governance of the project for the benefit of the community, with contributions from institutions including Caltech, TU Graz and Northwestern University.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$Does InvenioRDM assign DOIs?$q$, $q$Yes, it integrates with DataCite to automatically mint persistent DOIs for published records.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$What are alternatives to InvenioRDM?$q$, $q$Common alternatives include DSpace, Dataverse, Fedora, CKAN and the commercial platform Figshare.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$University research data repository$q$, $q$Universities host and publish FAIR datasets, code and publications produced by their researchers.$q$, $q$Academic libraries and research offices$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$National lab and consortium data archiving$q$, $q$Scientific consortia archive large-scale experimental and observational datasets with DOI-based citation.$q$, $q$National laboratories and research consortia$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$Institutional open-access publication repository$q$, $q$Institutions comply with funder open-data mandates by publishing citable, versioned outputs.$q$, $q$Research funders and compliance offices$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code access","Unlimited records and storage (infrastructure-dependent)","REST and OAI-PMH APIs","Community support via forums and GitHub"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$Managed Hosting (via partners)$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["Vendor-managed infrastructure","Implementation and customization support","Ongoing maintenance and upgrades","Optional SLA-backed support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$InvenioRDM is a free, open-source repository platform for managing and publishing research data, software and publications, built by CERN and a global community of research institutions on top of CERN's Invenio framework. It was designed as a turn-key rebuild that gives any institution the same repository capabilities that power Zenodo, the widely used European open-access research repository.$q$, $q$InvenioRDM's first demo-ready release, v1.0, arrived in February 2021, with the first production-suitable release (v6.0) following in August 2021. In October 2023, Zenodo itself completed its migration onto the InvenioRDM codebase, proving the platform can operate at massive scale across millions of records and petabytes of data.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform is built on a Python and Flask backend with PostgreSQL, OpenSearch/Elasticsearch and Celery/Redis, exposing REST and OAI-PMH APIs and a React-based frontend. It integrates with DataCite for DOI minting and supports ORCID and ROR persistent identifiers, controlled vocabularies, and metadata schemas aligned with FAIR data principles.$q$, $q$InvenioRDM supports community-based curation workflows, granular access controls and embargoes, and full record versioning, and it is designed to scale from small departmental archives to repositories with well over a hundred million records, deployable via Docker, Kubernetes, or traditional server infrastructure.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$InvenioRDM is free, open-source software with no license fee. Institutions download the codebase and self-host it on their own infrastructure, meaning the only ongoing cost is hosting, systems administration and any internal staff time devoted to customization and maintenance.$q$, $q$For institutions without in-house DevOps capacity, a small number of specialist consultancies and hosting partners affiliated with the Invenio community offer paid implementation and managed-hosting services layered on top of the free core software, providing an alternative to fully self-managed deployments.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1b860b3a-7f1c-4237-9c04-9f584f03194c', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
