INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$ISBN barcode scanning$q$, $q$Add books to a personal shelf by scanning barcodes or searching titles and authors.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$Wikidata-federated bibliographic database$q$, $q$Book, author and edition data is linked to and enriches the open Wikidata knowledge graph.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$Lending, selling and gifting tags$q$, $q$Mark individual book copies as available to lend, sell or give away to your network.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$Private groups and networks$q$, $q$Organize contacts into groups to control who can see and request items from your inventory.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$Wishlists$q$, $q$Track books you want so friends and network members can offer to lend or give them.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$Self-hostable federated instances$q$, $q$Run your own independent Inventaire instance while still connecting to the shared bibliographic database.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$Multilingual metadata$q$, $q$Book data inherits Wikidata's broad multilingual coverage for titles, authors and descriptions.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$In-app messaging$q$, $q$Private messaging tools to coordinate lending, borrowing or gifting arrangements.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$Completely free with no subscription or transaction fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$Open-source (AGPLv3) and self-hostable for privacy-conscious communities$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$Book data is federated with Wikidata rather than siloed, improving accuracy and openness$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$Nonprofit, community-governed model with no advertising-driven incentives$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$Well suited to local lending circles, reading groups and cooperative libraries$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$Smaller user base than mainstream platforms like Goodreads limits network effects$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$No integrated payments or shipping, so exchanges rely on manual, local coordination$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$Interface and feature set are more minimal than commercial book-tracking apps$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$Self-hosting a federated instance requires technical setup knowledge$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$Development pace is limited by a small volunteer and nonprofit team$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$What is Inventaire used for?$q$, $q$Inventaire is used to catalog personal book collections and let your network know which books are available to lend, sell or give away.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$Is Inventaire free?$q$, $q$Yes, Inventaire is entirely free to use, sustained through grants and donations rather than user fees.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$Is Inventaire open source?$q$, $q$Yes, the codebase is open source under the AGPLv3 license and available on Codeberg.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$How does Inventaire get its book data?$q$, $q$Inventaire reuses and contributes to Wikidata's open bibliographic graph rather than maintaining a proprietary book database.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$Can I self-host Inventaire?$q$, $q$Yes, anyone can deploy their own federated Inventaire instance instead of using the main inventaire.io site.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$What are Inventaire alternatives?$q$, $q$Common alternatives include Goodreads, LibraryThing, and other open-source library cataloguing tools.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$Personal library cataloguing$q$, $q$Casual readers track their book collections and share availability with friends.$q$, $q$Individual readers and book lovers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$Community lending libraries$q$, $q$Reading groups and cooperatives manage shared or circulating book collections.$q$, $q$Reading groups and community libraries$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$Open bibliographic data contribution$q$, $q$Wikimedia and open-data contributors enrich the Wikidata book graph while cataloguing their own collection.$q$, $q$Wikimedia and open-data communities$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$Hosted (inventaire.io)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full cataloguing and lending features","Wikidata-federated book data","Groups and messaging","No transaction fees"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$Self-Hosted$q$, $q$Free (open source)$q$, $q$N/A$q$, NULL, $q$["Run your own federated instance","Full control over data and hosting","AGPLv3-licensed source code","Community support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Inventaire is a free, open-source application for cataloguing personal book collections and connecting readers so they can lend, borrow, sell or give away books within their own social network. The project began around 2015 under French developer Maxime Lathuiliere and was formalized in 2019 as a French nonprofit association so its founders could work on it as paid staff.$q$, $q$Unlike commercial book-tracking apps, Inventaire is a community-governed, grant-funded project (notably supported by NLnet Foundation grants) rather than a venture-backed company, and its codebase is fully open source under the AGPLv3 license, with anyone free to run their own self-hosted, federated instance.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Inventaire's core innovation is that its book data is not a proprietary database but a CC0-licensed, Wikidata-federated bibliographic graph, linking books, authors and editions to Wikipedia and national library catalogs rather than maintaining a walled-garden metadata set. Users add books by scanning ISBN barcodes or searching titles, then tag copies as available to lend, sell or give away.$q$, $q$The platform supports private groups and networks so users can see what people they know currently have listed, private messaging to arrange exchanges, and wishlists, all with multilingual coverage inherited from Wikidata. There is deliberately no built-in payment or shipping system, since Inventaire is built around local, trust-based exchanges rather than a commercial marketplace model.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Inventaire is entirely free to use on its flagship instance at inventaire.io, with no subscription tiers, transaction fees or premium features gated behind a paywall. The project is sustained through grants (including NLnet Foundation funding) and donations rather than user fees.$q$, $q$Because the software is open source under AGPLv3, organizations and communities can also self-host their own federated Inventaire instance at no licensing cost, taking on only their own infrastructure costs in exchange for full control over their book data.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('17bcec27-a728-457f-9bcf-8278ac304f04', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$Parts and stock categorization$q$, $q$Organize parts into structured categories with custom fields and parameters.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$Barcode and QR scanning$q$, $q$Scan barcodes or QR codes to speed up stock check-in, check-out and audits.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$Bill of Materials management$q$, $q$Define BOMs showing which sub-parts and quantities are needed to build a new part.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$Build order tracking$q$, $q$Manage manufacturing builds that consume stock to produce finished parts.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$Purchase and sales order management$q$, $q$Track orders tied to suppliers and customers alongside stock levels.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$REST API and plugin system$q$, $q$Full API access and an extensible plugin architecture for custom integrations.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$Multi-warehouse stock locations$q$, $q$Track stock across multiple physical locations and warehouses.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$Mobile apps$q$, $q$Native Android and iOS apps for on-the-floor stock-taking and barcode scanning.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$Completely free and open source under the permissive MIT license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$Deep BOM and build-order tools tailored to electronics and hardware manufacturing$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$Self-hosted, so data stays fully under the organization's control$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$Extensible via a plugin architecture and full REST API$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$Active, fast-moving open-source community with frequent releases$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$Requires technical know-how (Docker, Python, database administration) to deploy and maintain$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$No official vendor support; help comes from community channels or paid consultancies$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$UI/UX is more utilitarian than polished commercial inventory tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$Self-hosting means the user bears responsibility for backups, security and uptime$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$Advanced features like plugins may require developer skills to configure$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$What is Inventree used for?$q$, $q$Inventree is an open-source system for tracking parts, stock levels, bills of materials and manufacturing builds.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$Is Inventree free?$q$, $q$Yes, the core software is free and open source under the MIT license, with no seat fees or feature paywalls.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$Does Inventree require self-hosting?$q$, $q$Yes, Inventree is designed to be self-hosted, though third-party providers offer paid managed-hosting options.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$Can Inventree manage bills of materials and builds?$q$, $q$Yes, it includes intelligent BOM management and a build-order system that consumes stock to produce finished parts.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$Is there a mobile app for Inventree?$q$, $q$Yes, native Android and iOS apps support barcode scanning and stock-taking on the go.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$What are Inventree alternatives?$q$, $q$Common alternatives include Fishbowl, Sortly, Odoo Inventory, PartKeepr and Zoho Inventory.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$Electronics manufacturing stock control$q$, $q$Manufacturers track components and their bills of materials across build stages.$q$, $q$Electronics and hardware manufacturers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$Makerspace and hobbyist inventory$q$, $q$Makerspaces and hobbyists manage shared component stock without licensing costs.$q$, $q$Makerspaces and hobbyist engineers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$Small manufacturer order workflows$q$, $q$Small manufacturers run purchase, sales and build order workflows in one system.$q$, $q$Small-to-medium manufacturing businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited parts, users and warehouses","Full REST API access","Plugin system","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$Managed Hosting (third-party)$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["Vendor-managed infrastructure","Deployment and customization support","Ongoing maintenance","Optional support agreements"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$InvenTree is a free, open-source inventory management system created in March 2017 by Australian electrical engineer Oliver Walters, originally to manage stock and bills of materials for his own electronics projects. It has since grown into a widely used community project on GitHub with dozens of contributors and a large, active user base.$q$, $q$Unlike a commercial vendor, InvenTree has no formal company or venture backing; it is maintained by Walters and a distributed group of volunteer contributors, sustained by community donations, with an ecosystem of third-party consultancies and hosting providers offering paid setup and managed-hosting on top of the free core software.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$InvenTree is built on a Python/Django backend with a full REST API, supporting PostgreSQL, MySQL or SQLite databases and a React/TypeScript frontend. Core functionality includes structured part categorization, barcode and QR-code scanning, multi-warehouse stock tracking, and intelligent Bill of Materials management showing exactly which sub-parts are required to build a new item.$q$, $q$A build-order system consumes stock to produce finished parts with automatic or manual allocation, while purchase-order and sales-order management ties suppliers and customers into the same system. An extensible plugin architecture lets developers add custom logic, labels, reports and third-party part-data integrations such as DigiKey, Mouser and LCSC without modifying the core codebase.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$InvenTree is released under the permissive MIT license, meaning the core software has no subscription fee or feature paywall: anyone can download, self-host and use it for unlimited parts, stock items, users and warehouses at zero licensing cost.$q$, $q$The only recurring cost is the organization's own server or cloud hosting bill. For teams without in-house DevOps resources, third-party consultancies and hosting providers offer paid deployment, customization and managed-hosting services on top of the free software.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
