INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7ecc3f02-c0cd-49b1-9080-12b8eb327cb3', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$ITIL-aligned incident and change management$q$, $q$Structured processes for incident, problem and change management following ITIL best practices.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$Self-service portal and knowledge base$q$, $q$End users submit and track requests while resolving common issues via a searchable knowledge base.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$Low-code workflow builder$q$, $q$Drag-and-drop configuration of ticket types, approval chains and automation rules.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$AI Service Agent$q$, $q$AI-powered virtual agent that triages and resolves common IT requests automatically.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$SLA and OLA management$q$, $q$Service-level tracking with escalation rules to keep tickets moving within agreed timeframes.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$Multi-department and multi-brand desks$q$, $q$Support multiple departments or brands from a single InvGate instance.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$Microsoft Teams, Slack and WhatsApp integrations$q$, $q$Native integrations letting end users and agents interact through familiar communication channels.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$Reporting and analytics$q$, $q$Built-in dashboards for tracking ticket volume, SLA compliance and team performance.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$Transparent published pricing, unusual among enterprise ITSM vendors$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$Unlimited free end-users and requesters on every plan$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$Fast, low-code implementation measured in weeks rather than months$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$ITIL-aligned processes without ServiceNow-level cost$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$AI Service Agent helps automate first-line triage$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$Starter plan is limited to 5 agents, requiring an upgrade for growing teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$Advanced integrations like Teams, WhatsApp and the AI agent are gated behind Pro/Enterprise tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$On-premise deployment is only available at the highest-cost Enterprise tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$Smaller third-party integration ecosystem than ServiceNow or Jira Service Management$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$Some reviewers note reporting customization is less flexible than larger competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$What is InvGate Service Desk used for?$q$, $q$InvGate Service Desk is an ITSM platform used to manage IT tickets, incidents, changes and requests following ITIL best practices.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$How much does InvGate Service Desk cost?$q$, $q$Pricing starts at 1,499 dollars per year for the Starter plan (5 agents), with Pro from roughly 500 dollars per agent per year and Enterprise from around 12,000 dollars per year.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$Is InvGate Service Desk ITIL-compliant?$q$, $q$Yes, it supports ITIL-aligned incident, problem, change and request management processes.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$Does InvGate offer on-premise deployment?$q$, $q$Yes, on-premise deployment is available at the Enterprise tier, while lower tiers are cloud-hosted SaaS.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$Does InvGate include AI features?$q$, $q$Yes, an AI Service Agent is available on Pro and Enterprise plans to triage and resolve common requests automatically.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$What are InvGate Service Desk alternatives?$q$, $q$Common alternatives include Freshservice, Jira Service Management, Zendesk for IT, SysAid and ServiceNow.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$IT help desk incident management$q$, $q$IT teams handle and track incident and request tickets with ITIL-aligned workflows.$q$, $q$Corporate IT help desks$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$Higher education IT services$q$, $q$Universities manage large volumes of unlimited free end-user requests across departments.$q$, $q$Higher-education and government IT departments$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$Mid-size enterprise ITSM migration$q$, $q$Growing enterprises replace legacy or overpriced ITSM tools with a faster, more affordable platform.$q$, $q$Mid-size enterprises$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$Starter$q$, $q$$1,499/year$q$, $q$Annual$q$, NULL, $q$["Up to 5 agents","Unlimited end users and approvers","SSO integration","Basic AI hub features"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$Pro$q$, $q$From $500/agent/year (from $2,500/year)$q$, $q$Annual$q$, NULL, $q$["5-50 agents","Low-code workflow builder","AI Service Agent","Microsoft Teams and WhatsApp integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$Enterprise$q$, $q$Custom (from $12,000/year)$q$, $q$Annual$q$, NULL, $q$["Unlimited agents","On-premise hosting option","Concurrent seat licensing","Multiple SAML/SSO configurations"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$InvGate is an IT service management company founded in 2008 in Buenos Aires, Argentina, by CEO Ariel Gesto and President Liliana Gary, built to deliver ITIL-aligned service desk software without the heavy consulting costs of legacy ITSM vendors. The company has grown into a global operation with employees across five continents while remaining privately held.$q$, $q$InvGate Service Desk is the company's flagship ITSM product, part of a broader InvGate Service Management suite that also includes IT asset management. It is positioned as a fast-to-implement, low-code alternative to enterprise incumbents like ServiceNow.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform provides ITIL-aligned incident, problem and change management, a self-service portal and knowledge base, and a low-code drag-and-drop workflow builder that lets administrators configure ticket types, approval chains and SLAs without professional services. An AI-powered virtual service agent triages and resolves common requests automatically.$q$, $q$InvGate supports multi-department and multi-brand support desks, SLA and OLA tracking with escalation rules, and native integrations with Microsoft Teams, Slack, WhatsApp and SSO providers, along with reporting dashboards and optional CMDB integration through InvGate's asset management product.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$InvGate publishes its pricing transparently: Starter costs a fixed 1,499 dollars per year for up to 5 agents, Pro starts around 500 dollars per agent per year for 5 to 50 agents and adds the workflow builder and AI Service Agent, and Enterprise starts around 12,000 dollars per year with custom, unlimited agent pricing and on-premise deployment options.$q$, $q$A distinguishing feature of InvGate's pricing model is that end users and approvers are unlimited and free on every tier, so organizations only pay for agent seats rather than every employee who submits a ticket, a structure that tends to undercut per-seat competitors for organizations with large end-user bases.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0de1e87e-9618-43ae-b91b-b9ceedf4e826', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Text-to-video AI generation$q$, $q$Generate a full edited video from a text prompt, script, blog post URL or product link.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$AI avatars and voice cloning$q$, $q$AI-generated talking presenters and cloned voices for narration and presentation-style videos.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Automatic script writing$q$, $q$AI writes a video script and selects matching stock footage, images and music automatically.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Multi-language translation and dubbing$q$, $q$Translate and dub videos into multiple languages for international audiences.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Timeline-based manual editor$q$, $q$Full editing timeline to refine AI-generated rough cuts with manual control.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Access to Sora 2 and Veo 3.1$q$, $q$Bundled access to OpenAI's Sora 2 and Google's Veo 3.1 generative video models in one subscription.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Stock media library$q$, $q$Integrated iStock footage, image and music library for video assembly.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Marketing and social templates$q$, $q$Large library of templates tailored to social media and marketing video formats.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Fast prompt-to-video workflow requires no editing experience$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Bundles multiple frontier AI video models, including Sora 2 and Veo 3.1, in one subscription$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Free tier available to test AI generation before paying$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Strong template library aimed at marketing and social content$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Voice cloning and multilingual dubbing built in$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$AI generation minutes are capped per plan and can run out quickly for heavy users$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Higher-quality outputs from premium models often consume credits faster$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Free plan exports carry watermarks and limited resolution$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Manual editor is less full-featured than dedicated tools like Premiere or Veed for complex edits$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Pricing can climb quickly for teams needing high-volume AI generation or multiple seats$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$What is InVideo used for?$q$, $q$InVideo is used to generate and edit marketing, social media and explainer videos from text prompts, scripts or existing content.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Is InVideo free?$q$, $q$InVideo offers a free tier with watermarked, limited exports; paid plans start around 20 dollars per month billed annually.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Does InVideo support AI avatars and voice cloning?$q$, $q$Yes, InVideo offers AI avatars and voice cloning as part of its generation tools.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$What AI video models does InVideo use?$q$, $q$InVideo bundles access to models including OpenAI's Sora 2 and Google's Veo 3.1 alongside its own generation engine.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Can I edit AI-generated videos manually in InVideo?$q$, $q$Yes, a full timeline-based editor lets users manually refine any AI-generated rough cut.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$What are InVideo alternatives?$q$, $q$Common alternatives include Synthesia, Pictory, HeyGen, Veed.io, Runway and Canva's video tools.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Social media marketing videos$q$, $q$Marketers produce short-form video ads and social content directly from a text brief.$q$, $q$Social media marketers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Content repurposing$q$, $q$Creators turn blog posts and articles into video summaries automatically.$q$, $q$Content creators and bloggers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Small business product videos$q$, $q$Small businesses create product and explainer videos without a dedicated editing team.$q$, $q$Small business owners$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Limited AI generation minutes","Watermarked exports","Access to templates","Basic editing tools"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Plus$q$, $q$~$20/month (annual) or ~$25-28/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["~50 AI generation minutes/month","~80 iStock downloads/month","2 voice clones","~120 voiceover minutes/month"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Max$q$, $q$~$48/month (annual) or ~$60/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["~200 AI generation minutes/month","~320 iStock downloads/month","5 voice clones","Priority rendering"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Enterprise / Generative$q$, $q$Custom (up to ~$899/month)$q$, $q$Custom$q$, NULL, $q$["High-volume AI generation minutes","Multiple seats","Premium support","Advanced brand controls"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$InVideo is an AI-powered video creation platform founded in 2017 by Sanket Shah, Harsh Vakharia, Pankit Chheda and Anshul Khandelwal, originally launched as a template-based editor for marketers before pivoting into generative AI video. The company is headquartered in San Francisco with a large team based in Mumbai, India.$q$, $q$InVideo has raised roughly 52.5 million dollars in funding from investors including Peak XV Partners and Tiger Global, and reports around 70 million dollars in annual recurring revenue as of 2026 with tens of millions of users across 150-plus countries.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$InVideo AI turns a single text prompt, script, blog post or product link into a complete edited video: it writes the script, selects stock footage and music, generates voiceovers with optional voice cloning, adds captions, and assembles a rough cut ready for review in a full timeline-based editor.$q$, $q$The platform also offers AI avatars, automatic translation and dubbing, and a large template library, and as of 2026 it bundles access to multiple third-party generative video models, including OpenAI's Sora 2 and Google's Veo 3.1, inside a single subscription rather than requiring separate accounts for each model.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$InVideo offers a free tier for testing AI video generation with watermarked, limited exports. The Plus plan runs roughly 20 dollars per month billed annually (25-28 dollars billed monthly) with around 50 AI generation minutes, while the Max plan runs roughly 48 dollars per month billed annually (about 60 dollars monthly) with roughly double the AI generation minutes and voice clones.$q$, $q$Higher business and enterprise-style plans extend pricing up toward several hundred dollars per month for teams that need larger AI-minute quotas, more seats and premium support; because generation minutes are metered, actual monthly cost can vary significantly with usage, especially when using premium models like Sora 2.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
