INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$Customizable invoices and quotes$q$, $q$Create branded invoices, quotes, purchase orders and credit notes across multiple templates.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$Recurring billing and reminders$q$, $q$Automate subscription billing cycles and send automated payment reminders to clients.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$Client portal with online payments$q$, $q$Clients view and pay invoices online through more than 40 supported payment gateways.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$Time and expense tracking$q$, $q$Track billable time and expenses tied to specific projects and tasks.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$E-invoicing and PEPPOL compliance$q$, $q$Support for e-invoicing standards and the PEPPOL network for European tax compliance.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$Full REST API$q$, $q$Programmatic access for integrating invoicing and billing data with other business systems.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$Multi-currency and multi-language support$q$, $q$Bill clients in their local currency and language across international markets.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$Self-hosting option$q$, $q$Deploy the full platform on your own server with no artificial client or feature limits.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$Free, unlimited self-hosted version with no artificial feature caps$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$Affordable hosted plans compared to FreshBooks or QuickBooks$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$Supports 40-plus payment gateways and multi-currency invoicing$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$Native desktop and mobile apps alongside the web app$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$Bootstrapped company with a long track record and stable pricing$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$Self-hosting requires technical setup with a PHP/Laravel server and database maintenance$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$The Elastic License v2 restricts reselling or offering it as a hosted service to others$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$Interface feels less polished than some modern SaaS competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$Free hosted plan is capped at just 5 clients$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$Advanced features like bank sync and e-invoicing credits are reserved for higher tiers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$Is Invoice Ninja free?$q$, $q$Yes, self-hosting is free forever with no client or invoice limits, and the hosted version includes a free plan capped at 5 clients.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$Can I self-host Invoice Ninja?$q$, $q$Yes, Invoice Ninja can be self-hosted for free via manual install, Docker, or a one-click auto-installer.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$What payment gateways does Invoice Ninja support?$q$, $q$Invoice Ninja supports more than 40 payment gateways, including Stripe, PayPal, Square and Braintree.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$Is Invoice Ninja open source?$q$, $q$The source code is publicly available under the Elastic License v2, which allows self-hosting and modification but restricts commercial resale.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$Does Invoice Ninja support recurring invoices?$q$, $q$Yes, it supports recurring and subscription billing with automated payment reminders.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$What are Invoice Ninja alternatives?$q$, $q$Common alternatives include FreshBooks, QuickBooks, Zoho Invoice, Wave and the open-source tool Crater.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$Freelance and consultant billing$q$, $q$Freelancers and consultants bill clients directly with recurring invoices and online payments.$q$, $q$Freelancers and independent consultants$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$Agency time and billing management$q$, $q$Small agencies track billable time and expenses across client projects and invoice accordingly.$q$, $q$Small agencies and service businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$Self-hosted, privacy-focused billing$q$, $q$Privacy-conscious businesses self-host their billing data instead of using a third-party SaaS provider.$q$, $q$Data-sovereignty-focused businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$Free (Hosted or Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Up to 5 clients (hosted) or unlimited (self-hosted)","Unlimited invoicing","4-11 invoice templates","Client portal and online payments"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$Ninja Pro$q$, $q$$14/month or $140/year$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited clients","Remove Invoice Ninja branding","Custom email and branded URL","API access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$Enterprise$q$, $q$$18-$300/month (by user count)$q$, $q$Monthly$q$, NULL, $q$["Multiple account users with permissions","File attachments","Bank account sync","E-invoicing and PEPPOL credits"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$Premium Business$q$, $q$Custom (from $280/year)$q$, $q$Annual$q$, NULL, $q$["Developer concierge","Priority support","Custom invoice design service","Data migration assistance"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Invoice Ninja is an invoicing, quoting, payments and time-tracking platform co-founded in 2014 by Hillel Coren and Shalom Stark, with Dave Michael joining as CTO in 2015. The company is a small, entirely bootstrapped team based in Haifa, Israel, with no outside venture funding, having grown the platform to over 200,000 accounts.$q$, $q$The current major version, v5, is a ground-up rewrite of the original v4 codebase, built on a Laravel PHP backend with Flutter and React-based frontends and mobile apps. Source code is public on GitHub under the Elastic License v2, which allows self-hosting and modification but restricts reselling the software as a hosted service to third parties.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Invoice Ninja supports creating and customizing invoices, quotes, purchase orders and credit notes across multiple templates, recurring and subscription billing with automated payment reminders, and a client portal where customers can view and pay invoices online through more than 40 payment gateways including Stripe, PayPal, Square and Braintree.$q$, $q$The platform also includes expense and time tracking tied to projects and tasks, basic inventory tracking, multi-currency and multi-language support, e-invoicing and PEPPOL network connectivity for European tax compliance, and a full REST API alongside native desktop apps for Windows, macOS and Linux and mobile apps for iOS and Android.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7a4e1855-1280-4e6d-addb-b37221f3a3ec', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Self-hosting Invoice Ninja is completely free forever with no artificial limits on clients, invoices or features, the only cost being the user's own server. On the hosted cloud side, a free plan is capped at 5 clients, while the Pro plan costs around 14 dollars per month and unlocks unlimited clients, custom branding and API access.$q$, $q$The Enterprise plan is priced per number of users, from around 18 dollars per month for 1-2 users up to roughly 300 dollars per month for 51-100 users, and adds multi-user permissions, bank feed sync and bundled e-invoicing/PEPPOL credits, while a custom-priced Premium Business tier adds a developer concierge and white-glove data migration for larger teams.$q$]::text[], 2);
